let v3dRenderer, v3dScene, v3dCamera, v3dGroup, v3dRunning = false, v3dViewerProjectId = null;
let v3dState, v3dDefault, v3dMaxDim;
let v3dLastW = 0, v3dLastH = 0;
let v3dControlsBound = false;

function init3DViewer() {
  const wrap = document.getElementById('v3d-wrap');

  // Create renderer once, reuse forever
  if (!v3dRenderer) {
    v3dRenderer = new THREE.WebGLRenderer({ antialias: true, logarithmicDepthBuffer: true });
    v3dRenderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    v3dRenderer.setClearColor(0x0c0c14, 1);
    v3dRenderer.toneMapping = THREE.ACESFilmicToneMapping;
    v3dRenderer.toneMappingExposure = 1.15;
    wrap.insertBefore(v3dRenderer.domElement, wrap.firstChild);
  }

  // Same project already loaded — nothing to rebuild
  var _projId = currentModalProject ? currentModalProject.id : null;
  if (v3dViewerProjectId === _projId && v3dGroup) return;
  v3dViewerProjectId = _projId;

  v3dScene = new THREE.Scene();
  v3dCamera = new THREE.PerspectiveCamera(52, 1, 0.1, 5000);
  v3dGroup = new THREE.Group();

  var _viewerGeo = (currentModalProject && currentModalProject.id === 3) ? PCB_GEO_CTRL : PCB_GEO;
  for (const m of _viewerGeo.meshes) {
    const geo = new THREE.BufferGeometry();
    geo.setAttribute('position', new THREE.Float32BufferAttribute(m.v, 3));
    geo.setIndex(m.i);
    geo.computeVertexNormals();
    const [r,g,b] = m.color;
    const isGold = (r > 0.6 && g > 0.5 && b < 0.4);
    const isSilver = (r > 0.68 && g > 0.68 && b > 0.68 && Math.abs(r-g) < 0.06);
    const mat = new THREE.MeshPhysicalMaterial({
      color: new THREE.Color(r, g, b),
      metalness: isGold ? 0.65 : isSilver ? 0.55 : 0.0,
      roughness: isGold ? 0.25 : isSilver ? 0.35 : 0.82,
    });
    v3dGroup.add(new THREE.Mesh(geo, mat));
  }

  // Rotate so board lies flat (VRML Z-up → Three.js Y-up)
  v3dGroup.rotation.x = -Math.PI / 2;
  v3dGroup.rotation.z = (currentModalProject && currentModalProject.id === 3) ? -Math.PI / 2 : 0;

  const box = new THREE.Box3().setFromObject(v3dGroup);
  const centre = new THREE.Vector3();
  box.getCenter(centre);
  v3dGroup.position.sub(centre);
  v3dScene.add(v3dGroup);

  // Recompute box after centering
  const box2 = new THREE.Box3().setFromObject(v3dGroup);
  const sz = new THREE.Vector3();
  box2.getSize(sz);
  v3dMaxDim = Math.max(sz.x, sz.y, sz.z);

  // Update camera clipping planes based on model size
  v3dCamera.near = v3dMaxDim * 0.01;
  v3dCamera.far = v3dMaxDim * 10;
  v3dCamera.updateProjectionMatrix();

  // Grid
  const grid = new THREE.GridHelper(v3dMaxDim * 3, 40, 0x141a28, 0x0e1320);
  grid.position.y = box2.min.y - 0.002;
  v3dScene.add(grid);

  // Lighting
  v3dScene.add(new THREE.AmbientLight(0x8898c8, 0.6));
  const key = new THREE.DirectionalLight(0xffffff, 0.95);
  key.position.set(1, 2, 1.5); v3dScene.add(key);
  const fill = new THREE.DirectionalLight(0xc0d4ff, 0.45);
  fill.position.set(-1.5, 1, -0.8); v3dScene.add(fill);
  const rim = new THREE.DirectionalLight(0x50e890, 0.2);
  rim.position.set(0, -1, -1.5); v3dScene.add(rim);

  // Default orbit state
  const defR = v3dMaxDim * 1.5;
  v3dDefault = { theta: -0.5, phi: 1.0, r: defR, tx: 0, ty: 0, tz: 0 };
  v3dState = { ...v3dDefault };
  updateV3dCam();

  // Controls — bind only once to avoid stacking listeners
  const cv = v3dRenderer.domElement;
  if (!v3dControlsBound) {
  v3dControlsBound = true;
  cv.addEventListener('contextmenu', function(e) { e.preventDefault(); });
  let drag = null;
  cv.addEventListener('mousedown', function(e) {
    drag = { b: e.button, x: e.clientX, y: e.clientY, s: Object.assign({}, v3dState) };
  });
  window.addEventListener('mouseup', function() { drag = null; });
  window.addEventListener('mousemove', function(e) {
    if (!drag) return;
    const dx = e.clientX - drag.x, dy = e.clientY - drag.y;
    if (drag.b === 0) {
      v3dState.theta = drag.s.theta - dx * 0.011;
      v3dState.phi = Math.max(0.04, Math.min(Math.PI - 0.04, drag.s.phi - dy * 0.011));
    } else if (drag.b === 2) {
      const ps = v3dState.r * 0.0013;
      v3dState.tx = drag.s.tx - Math.cos(v3dState.theta) * dx * ps;
      v3dState.ty = drag.s.ty + dy * ps;
      v3dState.tz = drag.s.tz + Math.sin(v3dState.theta) * dx * ps;
    }
    updateV3dCam();
  });
  cv.addEventListener('wheel', function(e) {
    e.preventDefault();
    v3dState.r = Math.max(v3dMaxDim * 0.1, Math.min(v3dMaxDim * 10, v3dState.r * (1 + e.deltaY * 0.0009)));
    updateV3dCam();
  }, { passive: false });

  // Touch
  let touch = null;
  cv.addEventListener('touchstart', function(e) {
    e.preventDefault();
    if (e.touches.length === 1) touch = { n: 1, x: e.touches[0].clientX, y: e.touches[0].clientY, s: Object.assign({}, v3dState) };
    else if (e.touches.length === 2) {
      const dx = e.touches[0].clientX - e.touches[1].clientX;
      const dy = e.touches[0].clientY - e.touches[1].clientY;
      touch = { n: 2, d: Math.hypot(dx, dy), s: Object.assign({}, v3dState) };
    }
  }, { passive: false });
  cv.addEventListener('touchmove', function(e) {
    e.preventDefault();
    if (!touch) return;
    if (touch.n === 1 && e.touches.length === 1) {
      v3dState.theta = touch.s.theta - (e.touches[0].clientX - touch.x) * 0.011;
      v3dState.phi = Math.max(0.04, Math.min(Math.PI - 0.04, touch.s.phi - (e.touches[0].clientY - touch.y) * 0.011));
      updateV3dCam();
    } else if (touch.n === 2 && e.touches.length >= 2) {
      const dx = e.touches[0].clientX - e.touches[1].clientX;
      const dy = e.touches[0].clientY - e.touches[1].clientY;
      v3dState.r = Math.max(v3dMaxDim * 0.1, Math.min(v3dMaxDim * 10, touch.s.r * (touch.d / Math.hypot(dx, dy))));
      updateV3dCam();
    }
  }, { passive: false });
  cv.addEventListener('touchend', function() { touch = null; });
  } // end v3dControlsBound

  // Buttons
  document.getElementById('v3d-reset').onclick = function() { Object.assign(v3dState, v3dDefault); updateV3dCam(); };
  document.getElementById('v3d-top').onclick = function() {
    v3dState.theta = Math.PI / 2; v3dState.phi = 0.04; v3dState.r = v3dMaxDim * 1.2;
    v3dState.tx = v3dState.ty = v3dState.tz = 0; updateV3dCam();
  };
  let wire = false;
  document.getElementById('v3d-wire').onclick = function() {
    wire = !wire;
    this.classList.toggle('active', wire);
    v3dGroup.children.forEach(function(m) { m.material.wireframe = wire; });
  };

  // Hint auto-hide
  const hint = document.getElementById('v3d-hint');
  setTimeout(function() { hint.classList.add('hidden'); }, 5000);
  cv.addEventListener('mousedown', function() { hint.classList.add('hidden'); }, { once: true });
}

function updateV3dCam() {
  const s = v3dState;
  v3dCamera.position.set(
    s.tx + s.r * Math.sin(s.phi) * Math.cos(s.theta),
    s.ty + s.r * Math.cos(s.phi),
    s.tz + s.r * Math.sin(s.phi) * Math.sin(s.theta)
  );
  v3dCamera.lookAt(s.tx, s.ty, s.tz);
}

function v3dLoop() {
  if (!v3dRunning) return;
  requestAnimationFrame(v3dLoop);
  const wrap = document.getElementById('v3d-wrap');
  const w = wrap.clientWidth, h = wrap.clientHeight;
  if (w > 0 && h > 0 && (v3dLastW !== w || v3dLastH !== h)) {
    v3dRenderer.setSize(w, h);
    v3dCamera.aspect = w / h;
    v3dCamera.updateProjectionMatrix();
    v3dLastW = w;
    v3dLastH = h;
  }
  v3dRenderer.render(v3dScene, v3dCamera);
}

// ── 3D PREVIEW THUMBNAIL ──
var prevRenderer, prevScene, prevCamera, prevGroup, prevAnim, prevRendererProjectId;
function initPreview3D() {
  var cv = document.getElementById('v3d-preview-canvas');
  var wrap = document.getElementById('v3d-preview');
  // Create renderer once and reuse forever — never dispose (avoids WebGL context loss)
  if (!prevRenderer) {
    prevRenderer = new THREE.WebGLRenderer({ canvas: cv, antialias: true, logarithmicDepthBuffer: true });
    prevRenderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    prevRenderer.setClearColor(0x0c0c14, 1);
    prevRenderer.toneMapping = THREE.ACESFilmicToneMapping;
    prevRenderer.toneMappingExposure = 1.15;
  }
  // Same project — just restart the spin, no rebuild needed
  if (prevRendererProjectId === currentModalProject.id && prevGroup) { startPreviewSpin(); return; }
  prevRendererProjectId = currentModalProject.id;
  // Clear old scene
  prevScene = new THREE.Scene();
  prevCamera = new THREE.PerspectiveCamera(48, 16/9, 1, 5000);
  prevGroup = new THREE.Group();

  var _previewGeo = (currentModalProject && currentModalProject.id === 3) ? PCB_GEO_CTRL : PCB_GEO;
  for (var mi = 0; mi < _previewGeo.meshes.length; mi++) {
    var m = _previewGeo.meshes[mi];
    var geo = new THREE.BufferGeometry();
    geo.setAttribute('position', new THREE.Float32BufferAttribute(m.v, 3));
    geo.setIndex(m.i);
    geo.computeVertexNormals();
    var r = m.color[0], g = m.color[1], b = m.color[2];
    var isGold = (r > 0.6 && g > 0.5 && b < 0.4);
    var isSilver = (r > 0.68 && g > 0.68 && b > 0.68 && Math.abs(r-g) < 0.06);
    var mat = new THREE.MeshPhysicalMaterial({
      color: new THREE.Color(r, g, b),
      metalness: isGold ? 0.65 : isSilver ? 0.55 : 0.0,
      roughness: isGold ? 0.25 : isSilver ? 0.35 : 0.82,
    });
    prevGroup.add(new THREE.Mesh(geo, mat));
  }
  prevGroup.rotation.x = -Math.PI / 2;
  prevGroup.rotation.z = (currentModalProject && currentModalProject.id === 3) ? -Math.PI / 2 : 0;
  var box = new THREE.Box3().setFromObject(prevGroup);
  var centre = new THREE.Vector3(); box.getCenter(centre);
  prevGroup.position.sub(centre);
  prevScene.add(prevGroup);

  prevScene.add(new THREE.AmbientLight(0x8898c8, 0.6));
  var k = new THREE.DirectionalLight(0xffffff, 0.95); k.position.set(1, 2, 1.5); prevScene.add(k);
  var fl = new THREE.DirectionalLight(0xc0d4ff, 0.45); fl.position.set(-1.5, 1, -0.8); prevScene.add(fl);

  var box2 = new THREE.Box3().setFromObject(prevGroup);
  var sz = new THREE.Vector3(); box2.getSize(sz);
  var maxD = Math.max(sz.x, sz.y, sz.z);
  prevCamera.near = maxD * 0.01; prevCamera.far = maxD * 10; prevCamera.updateProjectionMatrix();
  prevCamera.position.set(maxD * 0.75, maxD * 0.55, maxD * 0.75);
  prevCamera.lookAt(0, 0, 0);

  startPreviewSpin();
}

function startPreviewSpin() {
  if (prevAnim) cancelAnimationFrame(prevAnim);
  var angle = -0.5;
  function tick() {
    prevAnim = requestAnimationFrame(tick);
    var wrap = document.getElementById('v3d-preview');
    if (!wrap || wrap.style.display === 'none') { cancelAnimationFrame(prevAnim); prevAnim = null; return; }
    var w = wrap.clientWidth, h = wrap.clientHeight;
    if (w > 0 && h > 0) {
      prevRenderer.setSize(w, h);
      prevCamera.aspect = w / h;
      prevCamera.updateProjectionMatrix();
    }
    angle += 0.003;
    var box = new THREE.Box3().setFromObject(prevGroup);
    var sz = new THREE.Vector3(); box.getSize(sz);
    var dist = Math.max(sz.x, sz.y, sz.z) * 0.95;
    prevCamera.position.set(dist * Math.sin(angle) * 0.9, dist * 0.55, dist * Math.cos(angle) * 0.9);
    prevCamera.lookAt(0, 0, 0);
    prevRenderer.render(prevScene, prevCamera);
  }
  tick();
}

function stopPreviewSpin() {
  if (prevAnim) { cancelAnimationFrame(prevAnim); prevAnim = null; }
}

var IBOM_B64 = "";
var IBOM_B64_CTRL = "";
var ibomLoadedCtrl = false;
var ibomLoaded = false;
function openIBOM() {
  var ibomOverlay = document.getElementById('ibom-overlay');
  if (!ibomOverlay) return;
  var isCtrl = currentModalProject && currentModalProject.id === 3;
  var frame = document.getElementById('ibom-frame');
  if (isCtrl) {
    if (!ibomLoadedCtrl) {
      var html = decodeURIComponent(escape(atob(IBOM_B64_CTRL)));
      frame.src = URL.createObjectURL(new Blob([html], {type:'text/html'}));
      ibomLoadedCtrl = true;
    }
  } else {
    if (!ibomLoaded) {
      var html = decodeURIComponent(escape(atob(IBOM_B64)));
      frame.src = URL.createObjectURL(new Blob([html], {type:'text/html'}));
      ibomLoaded = true;
    }
  }
  // Update title
  var title = document.querySelector('#ibom-overlay .viewer-title');
  if (title) title.textContent = currentModalProject ? currentModalProject.title : 'PCB';
  ibomOverlay.classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeIBOM() {
  var ibomOverlay = document.getElementById('ibom-overlay');
  if (ibomOverlay) {
    ibomOverlay.classList.remove('open');
    document.body.style.overflow = '';
  }
}

function open3DViewer() {
  init3DViewer();
  var vt = document.getElementById('v3d-viewer-title');
  if (vt && currentModalProject) vt.textContent = currentModalProject.title;
  document.getElementById('viewer-overlay').classList.add('open');
  document.body.style.overflow = 'hidden';
  // Force resize on next frame so canvas matches the freshly visible container
  v3dLastW = 0;
  v3dLastH = 0;
  v3dRunning = true;
  // Reset hint
  document.getElementById('v3d-hint').classList.remove('hidden');
  setTimeout(function() { document.getElementById('v3d-hint').classList.add('hidden'); }, 5000);
  v3dLoop();
}

function close3DViewer() {
  document.getElementById('viewer-overlay').classList.remove('open');
  document.body.style.overflow = '';
  v3dRunning = false;
}
